body.value:
{%- style -%}
  .romira-timeline-{{ section.id }} {
    padding-top: {{ section.settings.mobile_padding_top }}px;
    padding-bottom: {{ section.settings.mobile_padding_bottom }}px;
    background-color: {{ section.settings.background_color }};
  }
  @media screen and (min-width: 750px) {
    .romira-timeline-{{ section.id }} {
      padding-top: {{ section.settings.padding_top }}px;
      padding-bottom: {{ section.settings.padding_bottom }}px;
    }
  }
  .romira-timeline-{{ section.id }} .rt-inner {
    max-width: {{ section.settings.content_width }}px;
    margin: 0 auto;
    padding: 0 {{ section.settings.horizontal_padding_mobile }}px;
  }
  @media screen and (min-width: 750px) {
    .romira-timeline-{{ section.id }} .rt-inner {
      padding: 0 {{ section.settings.horizontal_padding }}px;
    }
  }
  .romira-timeline-{{ section.id }} .rt-header {
    text-align: {{ section.settings.heading_alignment }};
    margin-bottom: 40px;
  }
  .romira-timeline-{{ section.id }} .rt-heading {
    font-size: {{ section.settings.heading_size_mobile }}px;
    color: {{ section.settings.heading_color }};
    margin: 0 0 12px;
    line-height: 1.2;
  }
  @media screen and (min-width: 750px) {
    .romira-timeline-{{ section.id }} .rt-heading {
      font-size: {{ section.settings.heading_size }}px;
    }
  }
  .romira-timeline-{{ section.id }} .rt-subheading {
    font-size: 16px;
    color: {{ section.settings.subheading_color }};
    margin: 0 auto;
    max-width: 680px;
    line-height: 1.5;
  }
  .romira-timeline-{{ section.id }} .rt-blocks {
    display: grid;
    grid-template-columns: 1fr;
    gap: {{ section.settings.block_gap_mobile }}px;
  }
  @media screen and (min-width: 750px) {
    .romira-timeline-{{ section.id }} .rt-blocks {
      grid-template-columns: repeat({{ section.blocks.size }}, 1fr);
      gap: {{ section.settings.block_gap }}px;
    }
  }
  .romira-timeline-{{ section.id }} .rt-block {
    background: {{ section.settings.block_bg_color }};
    border-radius: {{ section.settings.block_border_radius }}px;
    overflow: hidden;
    border-top: {{ section.settings.accent_bar_height }}px solid var(--rt-accent);
  }
  .romira-timeline-{{ section.id }} .rt-block-label {
    display: inline-block;
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    padding: 5px 14px;
    border-radius: 0 0 8px 0;
  }
  .romira-timeline-{{ section.id }} .rt-block-content {
    padding: {{ section.settings.block_padding_mobile }}px;
  }
  @media screen and (min-width: 750px) {
    .romira-timeline-{{ section.id }} .rt-block-content {
      padding: {{ section.settings.block_padding }}px;
    }
  }
  .romira-timeline-{{ section.id }} .rt-block-heading {
    font-size: {{ section.settings.block_heading_size_mobile }}px;
    margin: 10px 0 10px;
    line-height: 1.3;
  }
  @media screen and (min-width: 750px) {
    .romira-timeline-{{ section.id }} .rt-block-heading {
      font-size: {{ section.settings.block_heading_size }}px;
    }
  }
  .romira-timeline-{{ section.id }} .rt-block-text {
    font-size: {{ section.settings.block_text_size }}px;
    line-height: 1.6;
    margin: 0;
  }
  .romira-timeline-{{ section.id }} .rt-block-text p { margin: 0; }
{%- endstyle -%}

<div class="romira-timeline-{{ section.id }}">
  <div class="rt-inner">
    {%- if section.settings.heading != blank or section.settings.subheading != blank -%}
      <div class="rt-header">
        {%- if section.settings.heading != blank -%}
          <{{ section.settings.heading_tag }} class="rt-heading">{{ section.settings.heading }}</{{ section.settings.heading_tag }}>
        {%- endif -%}
        {%- if section.settings.subheading != blank -%}
          <p class="rt-subheading">{{ section.settings.subheading }}</p>
        {%- endif -%}
      </div>
    {%- endif -%}
    <div class="rt-blocks">
      {%- for block in section.blocks -%}
        <div class="rt-block" {{ block.shopify_attributes }} style="--rt-accent: {{ block.settings.accent_color }};">
          <div class="rt-block-label" style="background: {{ block.settings.accent_color }}; color: {{ block.settings.label_text_color }};">
            {{ block.settings.label }}
          </div>
          <div class="rt-block-content">
            {%- if block.settings.heading != blank -%}
              <h3 class="rt-block-heading" style="color: {{ block.settings.heading_color }};">{{ block.settings.heading }}</h3>
            {%- endif -%}
            {%- if block.settings.text != blank -%}
              <div class="rt-block-text" style="color: {{ block.settings.text_color }};">{{ block.settings.text }}</div>
            {%- endif -%}
          </div>
        </div>
      {%- endfor -%}
    </div>
  </div>
</div>

{% schema %}
{
  "name": "Romira — Timeline",
  "tag": "section",
  "class": "section",
  "settings": [
    { "type": "text", "id": "heading", "label": "Heading", "default": "What to Expect Week by Week" },
    { "type": "select", "id": "heading_tag", "label": "Heading tag", "options": [{"value":"h1","label":"H1"},{"value":"h2","label":"H2"},{"value":"h3","label":"H3"}], "default": "h2" },
    { "type": "range", "id": "heading_size", "min": 20, "max": 60, "step": 2, "unit": "px", "label": "Heading size (desktop)", "default": 36 },
    { "type": "range", "id": "heading_size_mobile", "min": 16, "max": 48, "step": 2, "unit": "px", "label": "Heading size (mobile)", "default": 26 },
    { "type": "select", "id": "heading_alignment", "label": "Heading alignment", "options": [{"value":"left","label":"Left"},{"value":"center","label":"Center"},{"value":"right","label":"Right"}], "default": "center" },
    { "type": "text", "id": "subheading", "label": "Subheading" },
    { "type": "color", "id": "heading_color", "label": "Heading color", "default": "#1a1a1a" },
    { "type": "color", "id": "subheading_color", "label": "Subheading color", "default": "#555555" },
    { "type": "color", "id": "background_color", "label": "Background color", "default": "#f8f8f6" },
    { "type": "color", "id": "block_bg_color", "label": "Card background", "default": "#ffffff" },
    { "type": "range", "id": "block_border_radius", "min": 0, "max": 24, "step": 2, "unit": "px", "label": "Card border radius", "default": 12 },
    { "type": "range", "id": "accent_bar_height", "min": 2, "max": 8, "step": 1, "unit": "px", "label": "Accent bar height", "default": 4 },
    { "type": "range", "id": "block_gap", "min": 8, "max": 48, "step": 4, "unit": "px", "label": "Gap between cards (desktop)", "default": 20 },
    { "type": "range", "id": "block_gap_mobile", "min": 8, "max": 48, "step": 4, "unit": "px", "label": "Gap between cards (mobile)", "default": 16 },
    { "type": "range", "id": "block_padding", "min": 8, "max": 40, "step": 4, "unit": "px", "label": "Card padding (desktop)", "default": 24 },
    { "type": "range", "id": "block_padding_mobile", "min": 8, "max": 40, "step": 4, "unit": "px", "label": "Card padding (mobile)", "default": 20 },
    { "type": "range", "id": "block_heading_size", "min": 14, "max": 28, "step": 1, "unit": "px", "label": "Card heading (desktop)", "default": 18 },
    { "type": "range", "id": "block_heading_size_mobile", "min": 14, "max": 28, "step": 1, "unit": "px", "label": "Card heading (mobile)", "default": 17 },
    { "type": "range", "id": "block_text_size", "min": 12, "max": 20, "step": 1, "unit": "px", "label": "Card text size", "default": 15 },
    { "type": "range", "id": "content_width", "min": 600, "max": 1400, "step": 20, "unit": "px", "label": "Max content width", "default": 1200 },
    { "type": "range", "id": "horizontal_padding", "min": 0, "max": 80, "step": 4, "unit": "px", "label": "Horizontal padding (desktop)", "default": 20 },
    { "type": "range", "id": "horizontal_padding_mobile", "min": 0, "max": 40, "step": 4, "unit": "px", "label": "Horizontal padding (mobile)", "default": 16 },
    { "type": "header", "content": "Spacing" },
    { "type": "range", "id": "padding_top", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding top (desktop)", "default": 60 },
    { "type": "range", "id": "padding_bottom", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding bottom (desktop)", "default": 60 },
    { "type": "range", "id": "mobile_padding_top", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding top (mobile)", "default": 36 },
    { "type": "range", "id": "mobile_padding_bottom", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding bottom (mobile)", "default": 36 }
  ],
  "blocks": [
    {
      "type": "phase",
      "name": "Timeline Phase",
      "settings": [
        { "type": "text", "id": "label", "label": "Phase label", "default": "WEEKS 1–2" },
        { "type": "text", "id": "heading", "label": "Phase heading", "default": "The Foundation Builds" },
        { "type": "richtext", "id": "text", "label": "Description", "default": "<p>R-ALA begins accumulating in nerve tissue. The cellular groundwork phase begins.</p>" },
        { "type": "color", "id": "accent_color", "label": "Accent color", "default": "#264165" },
        { "type": "color", "id": "label_text_color", "label": "Label text color", "default": "#ffffff" },
        { "type": "color", "id": "heading_color", "label": "Heading color", "default": "#1a1a1a" },
        { "type": "color", "id": "text_color", "label": "Text color", "default": "#444444" }
      ]
    }
  ],
  "presets": [
    {
      "name": "Romira — Timeline",
      "blocks": [
        { "type": "phase", "settings": { "label": "WEEKS 1–2", "heading": "The Foundation Builds", "text": "<p>R-ALA begins accumulating in nerve tissue. You may not feel dramatic changes yet — this is the cellular groundwork phase. Some customers notice mild improvements in sleep quality and reduced nighttime irritation.</p>" } },
        { "type": "phase", "settings": { "label": "WEEKS 3–4", "heading": "The Shift Begins", "text": "<p>Most customers start noticing real changes here. The burning and tingling that was worst at night begins to ease. Standing and walking feel less uncomfortable. Sleep improves noticeably.</p>" } },
        { "type": "phase", "settings": { "label": "WEEKS 5–8", "heading": "Sustained Relief", "text": "<p>Nerve comfort continues improving. Sensitivity in hands and feet reduces. Many customers describe feeling more comfortable, more mobile, and more rested than they have in years.</p>" } },
        { "type": "phase", "settings": { "label": "WEEKS 9–12+", "heading": "Long-Term Support", "text": "<p>With continued daily use, the improvements compound. Customers report the lowest levels of nerve discomfort in years. The 60-day guarantee gives you the full evaluation window.</p>" } }
      ]
    }
  ]
}
{% endschema %}
